// §267 SW-027. Deterministic assembly of the telemetry record. Cost is
// computed from token counts via config-driven per-model rates (Provider
// Adapter pricing table) — NO hardcoded prices (Principle 7). Confidence is
// platform-computed elsewhere (R-03/§295); SW-027 only records telemetry.
const j = $json;
const rates = $vars.CRIE_MODEL_RATES ? JSON.parse($vars.CRIE_MODEL_RATES) : {};
const r = rates[j.model] || { input: 0, output: 0 };
const inTok = Number(j.tokens?.input || 0);
const outTok = Number(j.tokens?.output || 0);
const estimated_cost = (inTok * (r.input || 0)) + (outTok * (r.output || 0));
return [{ json: {
  correlation_id: j.correlation_id,
  phase: j.phase || 'close',
  runtime_ms: Number(j.span?.runtime_ms || 0),
  input_tokens: inTok,
  output_tokens: outTok,
  provider: j.provider || null,
  model: j.model || null,
  retry_count: Number(j.retry_count || 0),
  success: j.success !== false,
  estimated_cost
} }];
